interface PaymentGateway {
    void charge(double amount);
}

class RazorpayGateway implements PaymentGateway {
    public void charge(double amount) {
        System.out.println("Charged via Razorpay: " + amount);
    }
}

class PhonePeGateway implements PaymentGateway {
    public void charge(double amount) {
        System.out.println("Charged via PhonePe: " + amount);
    }
}

class PaymentGatewayFactory {
    static PaymentGateway getGateway(String type) {
        return switch (type) {
            case "razorpay" -> new RazorpayGateway();
            case "phonepe" -> new PhonePeGateway();
            default -> throw new IllegalArgumentException("Unknown gateway: " + type);
        };
    }
}

