// Third-party class we cannot modify
class LegacyPaymentProcessor {
    void makePayment(String accountId, int amountInPaise) {
        System.out.println("Legacy processed: " + amountInPaise + " paise for " + accountId);
    }
}

// Our expected interface
interface PaymentGateway {
    void charge(String customerId, double amountInRupees);
}

// Adapter bridges the two
class LegacyPaymentAdapter implements PaymentGateway {
    private final LegacyPaymentProcessor legacyProcessor = new LegacyPaymentProcessor();

    public void charge(String customerId, double amountInRupees) {
        int paise = (int) (amountInRupees * 100);
        legacyProcessor.makePayment(customerId, paise);
    }
}

realWorldExample.code:
interface OrderService {
    Order placeOrder(OrderRequest request);
}

class DefaultOrderService implements OrderService {
    public Order placeOrder(OrderRequest request) {
        return new Order(request);
    }
}

// Decorator: adds logging without touching DefaultOrderService
class LoggingOrderServiceDecorator implements OrderService {
    private final OrderService delegate;
    LoggingOrderServiceDecorator(OrderService delegate) { this.delegate = delegate; }

    public Order placeOrder(OrderRequest request) {
        System.out.println("Placing order for: " + request.customerId());
        Order order = delegate.placeOrder(request);
        System.out.println("Order placed: " + order.id());
        return order;
    }
}

// Proxy: enforces an access check before delegating
class AuthorizationOrderServiceProxy implements OrderService {
    private final OrderService realService;
    AuthorizationOrderServiceProxy(OrderService realService) { this.realService = realService; }

    public Order placeOrder(OrderRequest request) {
        if (!request.customerIsVerified()) {
            throw new SecurityException("Customer not verified");
        }
        return realService.placeOrder(request);
    }
}

simpleExample.code:
interface DiscountStrategy {
    double apply(double amount);
}

class Order {
    private final double amount;
    private DiscountStrategy discountStrategy;

    Order(double amount) { this.amount = amount; }

    void setDiscountStrategy(DiscountStrategy strategy) {
        this.discountStrategy = strategy;
    }

    double finalPrice() {
        return discountStrategy.apply(amount);
    }
}

// Usage
Order order = new Order(2000.0);
order.setDiscountStrategy(amt -> amt * 0.9); // 10% off, as a lambda strategy

