@Service
class PaymentService {
    private final ApplicationEventPublisher publisher;

    PaymentService(ApplicationEventPublisher publisher) {
        this.publisher = publisher;
    }

    void completePayment(String paymentId, double amount) {
        // ... persist payment as COMPLETED ...
        publisher.publishEvent(new PaymentCompletedEvent(paymentId, amount));
    }
}

@Component
class NotificationService {
    @EventListener
    @Async
    void onPaymentCompleted(PaymentCompletedEvent event) {
        System.out.println("Sending SMS receipt for " + event.getPaymentId());
